import React, { useEffect, useMemo, useState } from 'react';
import { useNavigate } from 'react-router-dom';
import toast from 'react-hot-toast';
import { getExpenses, addExpense, deleteExpense } from '../api/expense.js';
import { removeToken } from '../utils/auth';
import ExpenseForm from '../components/ExpenseForm.jsx';
import ExpenseCard from '../components/ExpenseCard';
import EditExpenseModal from '../components/EditExpenseModal';

export default function Dashboard() {
  const navigate = useNavigate();

  const [expenses, setExpenses] = useState([]);
  const [loading, setLoading] = useState(true);
  const [submitting, setSubmitting] = useState(false);
  const [editingExpense, setEditingExpense] = useState(null);
  const [isModalOpen, setIsModalOpen] = useState(false);

  useEffect(() => {
    const fetchExpenses = async () => {
      try {
        const data = await getExpenses();
        setExpenses(data || []);
      } catch (err) {
        console.error(err);
      } finally {
        setLoading(false);
      }
    };
    fetchExpenses();
  }, []);

  const handleSubmit = async (data) => {
    try {
      setSubmitting(true);

      const payload = {
        amount: Number(data.amount),
        type: 'expense',
        category: data.title,
        date: data.date,
      };

      const newTx = await addExpense(payload);
      setExpenses((prev) => [newTx, ...prev]);
    } catch (err) {
      console.error(err);
    } finally {
      setSubmitting(false);
    }
  };

  const handleDelete = async (id) => {
    try {
      await deleteExpense(id);
      setExpenses((prev) => prev.filter((exp) => exp._id !== id));
    } catch (err) {
      console.error(err);
    }
  };

  const handleEdit = (expense) => {
    setEditingExpense(expense);
    setIsModalOpen(true);
  };

  const totalExpenses = expenses.reduce(
    (acc, t) => acc + Number(t.amount || 0),
    0
  );

  return (
    <div style={{ padding: "20px", color: "white" }}>

      <h1 style={{ fontSize: "24px", marginBottom: "20px" }}>
        Dashboard Working ✅
      </h1>

      <h2>Total: ₹{totalExpenses}</h2>

      <div style={{ marginTop: "20px" }}>
        <ExpenseForm onSubmit={handleSubmit} submitting={submitting} />
      </div>

      <div style={{ marginTop: "20px" }}>
        {loading ? (
          <p>Loading...</p>
        ) : (
          expenses.map((tx) => (
            <ExpenseCard
              key={tx._id}
              expense={tx}
              onEdit={handleEdit}
              onDelete={handleDelete}
              deleting={false}
            />
          ))
        )}
      </div>

      <EditExpenseModal
        isOpen={isModalOpen}
        onClose={() => setIsModalOpen(false)}
        expense={editingExpense}
        onUpdate={(data) => console.log(data)}
      />

    </div>
  );
}